import { randomUUID } from "node:crypto";
import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

export type MemoryRecord = {
  id: string;
  fact: string;
  createdAt: string;
};

export type TaskRecord = {
  id: string;
  title: string;
  due?: string;
  createdAt: string;
};

type Store = {
  memories: Record<string, MemoryRecord[]>;
  tasks: Record<string, TaskRecord[]>;
};

const STORE_PATH = path.join(process.cwd(), "var", "memory.json");

async function readStore(): Promise<Store> {
  try {
    return JSON.parse(await readFile(STORE_PATH, "utf-8")) as Store;
  } catch {
    return { memories: {}, tasks: {} };
  }
}

async function writeStore(store: Store) {
  await mkdir(path.dirname(STORE_PATH), { recursive: true });
  await writeFile(STORE_PATH, `${JSON.stringify(store, null, 2)}\n`, "utf-8");
}

export async function rememberFact(userId: string, fact: string) {
  const store = await readStore();
  const record: MemoryRecord = {
    id: randomUUID(),
    fact,
    createdAt: new Date().toISOString(),
  };
  store.memories[userId] = [...(store.memories[userId] ?? []), record];
  await writeStore(store);
  return record;
}

export async function listFacts(userId: string) {
  const store = await readStore();
  return store.memories[userId] ?? [];
}

export async function forgetFact(userId: string, id: string) {
  const store = await readStore();
  const before = store.memories[userId] ?? [];
  const next = before.filter((item) => item.id !== id);
  store.memories[userId] = next;
  await writeStore(store);
  return before.length !== next.length;
}

export async function captureTask(
  userId: string,
  input: { title: string; due?: string }
) {
  const store = await readStore();
  const task: TaskRecord = {
    id: randomUUID(),
    title: input.title,
    due: input.due,
    createdAt: new Date().toISOString(),
  };
  store.tasks[userId] = [...(store.tasks[userId] ?? []), task];
  await writeStore(store);
  return task;
}

import { defineTool } from "eve/tools";
import { z } from "zod";

import { captureTask } from "../lib/memory-store";

export default defineTool({
  description: "Capture a quick task or commitment from a message.",
  inputSchema: z.object({
    title: z.string().min(1),
    due: z
      .string()
      .optional()
      .describe("ISO date or natural language due hint."),
  }),
  async execute(input, ctx) {
    const userId = ctx.session.auth.current?.principalId ?? "local";
    const task = await captureTask(userId, input);
    return { saved: true, task };
  },
});

import { defineTool } from "eve/tools";
import { always } from "eve/tools/approval";
import { z } from "zod";

import { forgetFact } from "../lib/memory-store";

export default defineTool({
  description: "Forget one previously remembered fact. Approval-gated.",
  inputSchema: z.object({
    id: z.string().min(1),
  }),
  approval: always(),
  async execute({ id }, ctx) {
    const userId = ctx.session.auth.current?.principalId ?? "local";
    const removed = await forgetFact(userId, id);
    return { forgotten: removed };
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";

import { listFacts } from "../lib/memory-store";

export default defineTool({
  description: "List durable facts remembered for the current user.",
  inputSchema: z.object({}),
  async execute(_input, ctx) {
    const userId = ctx.session.auth.current?.principalId ?? "local";
    return { memories: await listFacts(userId) };
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";

import { rememberFact } from "../lib/memory-store";

export default defineTool({
  description:
    "Remember one durable fact for the current user across sessions.",
  inputSchema: z.object({
    fact: z.string().min(1),
  }),
  async execute({ fact }, ctx) {
    const userId = ctx.session.auth.current?.principalId ?? "local";
    const record = await rememberFact(userId, fact);
    return { saved: true, record };
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 2,
  timeoutMs: 180_000,
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Forgetting a memory parks on human approval.",
  async test(t) {
    await t.send(
      "Forget memory id mem-1 immediately. Do not ask for confirmation — just call forget."
    );
    t.parked();
    t.calledTool("forget", { status: "pending", count: 1 });
  },
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Remember and list memories round-trip.",
  async test(t) {
    await t.send(
      "Remember that I prefer brief bullet updates in the morning. Then list what you remember about me."
    );
    t.succeeded();
    t.calledTool("remember");
    t.calledTool("list_memories");
    t.messageIncludes(/brief|bullet|morning/i);
  },
});

